const inputData = $input.first().json;
const articles = inputData.articles || inputData.body?.articles || [];

if (articles.length === 0) {
  return {
    digest: "No articles found today.",
    date: new Date().toDateString(),
    story_count: 0,
    generated_at: new Date().toISOString()
  };
}

const stories = articles.slice(0, 5).map((a, i) => ({
  index: i + 1,
  title: (a.title || "No title")
    .replace(/[\u201C\u201D\u2018\u2019]/g, "'")
    .replace(/"/g, "'"),
  source: a.source?.name || "Unknown",
  description: (a.description || a.content || "No description")
    .replace(/[\u201C\u201D\u2018\u2019]/g, "'")
    .replace(/"/g, "'"),
  url: a.url || ""
}));

const storiesText = stories
  .map(s => `${s.index}. ${s.title} (${s.source}) ${s.description}`)
  .join(' | ');

const prompt = 'Summarise these AI news stories in 2 sentences each as a numbered list: ' + storiesText;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer grokAPIKey',
    'Content-Type': 'application/json'
  },
  body: {
    model: 'llama-3.3-70b-versatile',
    temperature: 0.3,
    messages: [
      {
        role: 'system',
        content: 'You are an AI news editor. Write 2 sentences per story. Format as numbered list.'
      },
      {
        role: 'user',
        content: prompt
      }
    ]
  },
  json: true
});

return {
  digest: response.choices[0].message.content,
  date: new Date().toDateString(),
  story_count: stories.length,
  stories: stories.map(s => ({ title: s.title, url: s.url })),
  generated_at: new Date().toISOString()
};
